 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import AddBootableVolumeLink from '@catalog/CreateFromInstanceTypes/components/AddBootableVolumeLink/AddBootableVolumeLink';
 5	import BootableVolumeOSIcons from '@catalog/CreateFromInstanceTypes/components/BootableVolumeEmptyState/BootableVolumeOSIcons';
 6	import useInstanceTypesAndPreferences from '@catalog/CreateFromInstanceTypes/state/hooks/useInstanceTypesAndPreferences';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { EmptyState, Title } from '@patternfly/react-core';
 9	
10	import './BootableVolumeEmptyState.scss';
11	
12	const BootableVolumeEmptyState: FC = () => {
13	  const { t } = useKubevirtTranslation();
14	  const { loadError } = useInstanceTypesAndPreferences();
15	
16	  return (
17	    <EmptyState>
18	      <div className="bootable-volume-empty-state">
19	        <Trans ns="plugin__kubevirt-plugin" t={t}>
20	          <Title className="bootable-volume-empty-state__title" headingLevel="h3">
21	            No volumes found
22	          </Title>
23	          To add a bootable volume, click <AddBootableVolumeLink loadError={loadError} /> Add volume
24	        </Trans>
25	        <BootableVolumeOSIcons />
26	      </div>
27	    </EmptyState>
28	  );
29	};
30	
31	export default BootableVolumeEmptyState;

